import{_ as e,c as o,o as i,a2 as t}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Privacy Choices","description":"","frontmatter":{},"headers":[],"relativePath":"guide/privacy-choices.md","filePath":"guide/privacy-choices.md","lastUpdated":1783607180000}'),s={name:"guide/privacy-choices.md"};function l(r,a,n,c,d,p){return i(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="privacy-choices" tabindex="-1">Privacy Choices <a class="header-anchor" href="#privacy-choices" aria-label="Permalink to &quot;Privacy Choices&quot;">​</a></h1><p>NueZip is a fully offline application. Because all your data stays on your device, we do not collect, sell, or share any personal information.</p><h2 id="data-we-hold-locally" tabindex="-1">Data We Hold Locally <a class="header-anchor" href="#data-we-hold-locally" aria-label="Permalink to &quot;Data We Hold Locally&quot;">​</a></h2><p>NueZip stores all data locally on your Mac:</p><ul><li>App preferences and configuration</li><li>Recent file list</li><li>Debug logs (if enabled)</li><li>Keychain-stored passwords (if you choose to save them)</li></ul><p>None of this data is uploaded to any server.</p><h2 id="your-rights" tabindex="-1">Your Rights <a class="header-anchor" href="#your-rights" aria-label="Permalink to &quot;Your Rights&quot;">​</a></h2><p>Since NueZip does not collect or store personal data on our servers, there is no personal data for us to access, delete, or transfer. All your data can be managed directly within the app or by removing the app&#39;s container folder:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Containers/com.nuezip.app</span></span></code></pre></div><h2 id="do-not-sell" tabindex="-1">Do Not Sell <a class="header-anchor" href="#do-not-sell" aria-label="Permalink to &quot;Do Not Sell&quot;">​</a></h2><p>NueZip does not sell any personal information. We do not use third-party analytics, advertising, or tracking services of any kind.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>If you have questions about privacy choices, open an issue at: <code>https://github.com/nuezip/nuezip/issues</code></p>',13)])])}const y=e(s,[["render",l]]);export{u as __pageData,y as default};
